  if(!userList.isEmpty()){
for(String s:userList){
 String[] sa = s.split("#");
 String email = sa[0];
 String lname = sa[1];
 String fname = sa[2];
 
	QueryOptions qo = new QueryOptions();
	//Filter filter = Filter.ignoreCase(Filter.and(Filter.like("email", email,Filter.MatchMode.START), Filter.eq("firstname",fname), Filter.eq("lastname",lname)));
  Filter filter = Filter.ignoreCase(Filter.and(Filter.eq("firstname",fname), Filter.eq("lastname",lname)));
	qo.addFilter(filter);
	qo.setCloneResults(true);
  //return filter;
  Iterator i = context.search(Identity.class,qo);
	if(null != i @and i.hasNext()){
    
		Identity idn = (Identity) i.next();
    //return idn;
		if(null != idn){
    // return idn;
			List assignments = idn.getAttributeAssignments();
      if(assignments != null @and !assignments.isEmpty()){
        
				for (Object asgObj : assignments){
					AttributeAssignment assignment = (AttributeAssignment)asgObj;
					if(assignment.getApplicationName().equalsIgnoreCase(appName)){    
						aaVal = assignment.getNativeIdentity() + "," + assignment.getStringValue()+","+idn.getName()+","+idn.isInactive();
						outList.add(aaVal);
					}
				}
      }else{
       outList.add(idn.getName()+","+idn.getLastname()+","+idn.getFirstname()+",----NO ATTRIBUTE ASSIGNMENT FOUND,"+idn.getEmail()); 
      }
		}
		
	}
  outList.add(s+",NO IDENTITY FOUND"); 
}
  }
return outList;
